import { Component, OnInit, OnDestroy, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Router, RouterModule } from '@angular/router';
import { Subscription, forkJoin, of, Observable } from 'rxjs';
import { catchError } from 'rxjs/operators';

import { User, Timbratura, Company } from '../../models';
import { AuthService } from '../../services/timbrature-auth.adapter';
import { CompanyService } from '../../services/company.service';
import { TimbratureService } from '../../services/timbrature.service';
import { UsersService } from '../../services/user.service';
import { LUCIDE_ICONS, LucideAngularModule } from 'lucide-angular';

@Component({
  selector: 'app-home',
  standalone: true,
  imports: [CommonModule, RouterModule, LucideAngularModule],
  templateUrl: './home.component.html',
  styleUrls: ['./home.component.css']
})
export class HomeComponent implements OnInit, OnDestroy {

  private authService = inject(AuthService);
  private companyService = inject(CompanyService);
  public timbratureService = inject(TimbratureService);
  private usersService = inject(UsersService);
  private router = inject(Router);

  currentUser: User | null = null;
  company: Company | null = null;
  timbrature: Timbratura[] = [];
  todaysTimbratura: Timbratura | null = null;
  dipendenti: User[] = [];
  isLoading = true;

  private subscriptions = new Subscription();

constructor() {}

  ngOnInit(): void {
this.authService.currentUser$.subscribe(user => {
  this.currentUser = user as any;
  const companyId = this.authService.companyId;
  if (companyId) {
    this.caricaDatiHome(companyId);
  } else {
    this.isLoading = false;
  }
})

  }

  ngOnDestroy(): void {
    this.subscriptions.unsubscribe();
  }

  private caricaDatiHome(companyId: string): void {
    this.isLoading = true;

    // 1. Azienda
    const company$: Observable<Company | null> = this.companyService.getById(companyId).pipe(
      catchError(err => {
        console.error('Errore nel caricamento azienda:', err);
        return of(null);
      })
    );

    // 2. Timbrature in base al ruolo
    let timbrature$: Observable<Timbratura[]>;
    if (this.authService.hasRole('employee')) {
      timbrature$ = this.timbratureService.fetchTimbrature({ userId: this.currentUser?.id ?? '', orderAsc: false }).pipe(
        catchError(err => {
          console.error('Errore nel caricamento timbrature:', err);
          return of([] as Timbratura[]);
        })
      );
    } else {
      // admin o manager: tutte le timbrature dell'azienda
      timbrature$ = this.timbratureService.fetchTimbrature({ companyId, orderAsc: false }).pipe(
        catchError(err => {
          console.error('Errore nel caricamento timbrature:', err);
          return of([] as Timbratura[]);
        })
      );
    }

    // 3. Dipendenti (solo per admin/manager)
    let dipendenti$: Observable<User[]> = of([] as User[]);
    if (this.hasRole('admin') || this.hasRole('manager')) {
      dipendenti$ = this.usersService.getByCompany(companyId).pipe(
        catchError(err => {
          console.error('Errore nel caricamento dipendenti:', err);
          return of([] as User[]);
        })
      );
    }

    // Esegui tutte le richieste in parallelo
    this.subscriptions.add(
      forkJoin({
        company: company$,
        timbrature: timbrature$,
        dipendenti: dipendenti$
      }).subscribe({
        next: (result) => {
          this.company = result.company;
          this.timbrature = result.timbrature;
          this.dipendenti = result.dipendenti;
          this.updateTodayTimbratura();
          this.isLoading = false;
        },
        error: (err) => {
          console.error('Errore nel caricamento dati home:', err);
          this.isLoading = false;
        }
      })
    );
  }

  hasRole(role: string): boolean {
    return this.authService.hasRole(role);
  }

  // --- Metodi statistiche ---
  getOreLavorateSettimana(): number {
    if (!this.timbrature || this.timbrature.length === 0) return 0;
    const { inizioSettimana, oggi } = this.getIntervaloSettimanaCorrente();
    const timbratureSettimana = this.timbrature.filter(t => {
      if (!t.end_ts) return false;
      const dataTimbratura = new Date(t.start_ts);
      return dataTimbratura >= inizioSettimana && dataTimbratura <= oggi;
    });
    let timbratureDaContare = timbratureSettimana;
    if (this.authService.hasRole('employee')) {
      timbratureDaContare = timbratureSettimana.filter(t => t.user_id === this.currentUser?.id);
    }
    const minutiTotali = timbratureDaContare.reduce((total, t) => total + (t.total_minutes || 0), 0);
    return minutiTotali / 60;
  }

  getTimbratureOggi(): number {
    if (!this.timbrature || this.timbrature.length === 0) return 0;
    const oggi = new Date(); oggi.setHours(0,0,0,0);
    const domani = new Date(oggi); domani.setDate(domani.getDate()+1);
    const timbratureOggi = this.timbrature.filter(t => {
      const d = new Date(t.start_ts);
      return d >= oggi && d < domani;
    });
    if (this.authService.hasRole('employee')) {
      return timbratureOggi.filter(t => t.user_id === this.currentUser?.id).length;
    }
    return timbratureOggi.length;
  }

  getDipendentiAttivi(): number {
    return this.dipendenti.filter(d => d.is_active).length;
  }

  getOreLavorateMese(): number {
    if (!this.timbrature || !this.timbrature.length) return 0;
    const now = new Date();
    const year = now.getFullYear();
    const month = now.getMonth();
    let totalMinutes = 0;
    for (const t of this.timbrature) {
      if (!t?.start_ts) continue;
      const start = new Date(t.start_ts);
      if (start.getFullYear() !== year || start.getMonth() !== month) continue;
      if (t.total_minutes) {
        totalMinutes += t.total_minutes;
      } else if (t.end_ts) {
        const end = new Date(t.end_ts);
        const diff = Math.max(0, Math.round((end.getTime() - start.getTime()) / 60000));
        totalMinutes += diff;
      }
    }
    return totalMinutes / 60;
  }

  // --- Metodi per timbratura ---
  async nuovaTimbraturaWithCheck(): Promise<void> {
    try {
      if (!this.currentUser) {
        this.router.navigate(['/crea-timbratura']);
        return;
      }
      const timbrature = await this.timbratureService.fetchTimbrature({ userId: this.currentUser.id }).toPromise();
      const oggi = new Date(); oggi.setHours(0,0,0,0);
      const domani = new Date(oggi); domani.setDate(domani.getDate()+1);
      const found = timbrature?.find(t => {
        const d = new Date(t.start_ts);
        return d >= oggi && d < domani;
      });
      if (found) {
        const ingressTime = new Date(found.start_ts).toLocaleTimeString('it-IT', { hour: '2-digit', minute: '2-digit' });
        const ok = window.confirm(`È già presente una timbratura oggi con ingresso alle ${ingressTime}.\nVuoi modificarla?`);
        if (ok) {
          this.router.navigate(['/crea-timbratura'], { queryParams: { edit: found.id, mode: 'edit' } });
        }
      } else {
        this.router.navigate(['/crea-timbratura']);
      }
    } catch (err) {
      console.error('[Home] nuovaTimbraturaWithCheck error', err);
      this.router.navigate(['/crea-timbratura']);
    }
  }

  private updateTodayTimbratura(): void {
    this.todaysTimbratura = null;
    if (!this.currentUser || !this.timbrature.length) return;
    const today = new Date(); today.setHours(0,0,0,0);
    const tomorrow = new Date(today); tomorrow.setDate(today.getDate()+1);
    const found = this.timbrature.find(t => {
      if (!t?.start_ts) return false;
      const d = new Date(t.start_ts);
      return d >= today && d < tomorrow && (this.authService.hasRole('admin') || t.user_id === this.currentUser?.id);
    });
    this.todaysTimbratura = found || null;
  }

  private getIntervaloSettimanaCorrente(): { inizioSettimana: Date; oggi: Date } {
    const oggi = new Date(); oggi.setHours(23,59,59,999);
    const giornoSettimana = oggi.getDay();
    const giorniDaLunedi = giornoSettimana === 0 ? 6 : giornoSettimana - 1;
    const inizioSettimana = new Date(oggi);
    inizioSettimana.setDate(oggi.getDate() - giorniDaLunedi);
    inizioSettimana.setHours(0,0,0,0);
    return { inizioSettimana, oggi };
  }


  get isAdmin(): boolean { return this.authService.hasRole('admin'); }
get isManager(): boolean { return this.authService.hasRole('manager'); }
get isEmployee(): boolean { return this.authService.hasRole('employee'); }
}
